import subprocess,os,json,datetime,urllib.request,base64,time
M4='192.168.10.94'; M4U='Alias'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
TS=datetime.datetime.now().strftime('%Y-%m-%d %H:%M')

def ssh(c,t=20):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8',
        M4U+'@'+M4,c],capture_output=True,text=True,timeout=t)
    return r.stdout.strip(),r.stderr.strip()

def run(c,shell=False,t=20):
    r=subprocess.run(c,shell=shell,capture_output=True,text=True,timeout=t)
    return r.stdout.strip(),r.stderr.strip()

print('='*55)
print('FINAL FIX: MEDIA.HTML + M4 FIREWALL + WEBSERVER')
print(TS)
print('='*55)

# 1. Find web root on MSI
print('\n[1] Finding web root...')
web_root=None
pid_out,_=run('ss -tlnp | grep 8888 || lsof -ti:8888 2>/dev/null',shell=True)
print(f'  Port 8888 info: {pid_out[:100]}')
ws_scripts,_=run("find /home/k -name '*.py' | xargs grep -l '8888' 2>/dev/null | head -5",shell=True,t=15)
print(f'  Webserver scripts: {ws_scripts[:200]}')
for ws in ws_scripts.split('\n'):
    ws=ws.strip()
    if ws and os.path.exists(ws):
        content=open(ws).read()
        import re
        matches=re.findall(r'["\']([/\w\-\.]+(?:vnt-web|public|html|www)[/\w\-\.]*)["\']',content)
        if matches:
            for m in matches:
                if os.path.isdir(m): web_root=m; print(f'  Found root: {m}')
if not web_root:
    for d in ['/home/k/vnt-web','/home/k/public','/var/www/html','/home/k']:
        if os.path.isdir(d): web_root=d; break
print(f'  Using web root: {web_root}')

# 2. Write media.html from b64
print('\n[2] Writing media.html...')
html_data=base64.b64decode('')
os.makedirs(web_root,exist_ok=True)
media_path=web_root+'/media.html'
open(media_path,'wb').write(html_data)
print(f'  Written: {media_path} ({len(html_data)} bytes)')

# 3. Ensure webserver running
print('\n[3] Ensuring webserver on 8888...')
try:
    urllib.request.urlopen('http://127.0.0.1:8888/media.html',timeout=4)
    print('  Port 8888: SERVING media.html OK')
except:
    run('fuser -k 8888/tcp 2>/dev/null',shell=True)
    time.sleep(1)
    subprocess.Popen(['python3','-m','http.server','8888','--directory',web_root],
        stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL)
    time.sleep(3)
    try:
        urllib.request.urlopen('http://127.0.0.1:8888/media.html',timeout=4)
        print('  Port 8888: NOW SERVING')
    except Exception as e:
        print(f'  Port 8888 FAILED: {e}')

# 4. Disable M4 firewall completely
print('\n[4] Disabling M4 firewall...')
ssh('/usr/libexec/ApplicationFirewall/socketfilterfw --setglobalstate off 2>/dev/null || true')
ssh('sudo /usr/libexec/ApplicationFirewall/socketfilterfw --setglobalstate off 2>/dev/null || true')
ssh('sudo pfctl -d 2>/dev/null || true')
